import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        // Convert input to appropriate types
        int numNodes = (int) n;
        int numEdges = edges.length;
        int upgradesLeft = (int) k;

        // Separate must and optional edges
        List<Edge> mustEdges = new ArrayList<>();
        List<Edge> optionalEdges = new ArrayList<>();

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int s = (int) edge[2];
            int must = (int) edge[3];
            if (must == 1) {
                mustEdges.add(new Edge(u, v, s, must));
            } else {
                optionalEdges.add(new Edge(u, v, s, must));
            }
        }

        // Sort optional edges by descending strength (after potential upgrade)
        Collections.sort(optionalEdges, (a, b) -> Integer.compare(b.s * 2, a.s * 2));

        // Initialize Union-Find
        UnionFind uf = new UnionFind(numNodes);

        // First, add all must edges to the spanning tree
        for (Edge edge : mustEdges) {
            uf.union(edge.u, edge.v);
        }

        // If must edges already form cycles, return -1
        if (uf.count == 1) {
            // All nodes are connected by must edges, need to find min strength
            int minStrength = Integer.MAX_VALUE;
            for (Edge edge : mustEdges) {
                minStrength = Math.min(minStrength, edge.s);
            }
            return minStrength;
        }

        // Now, try to connect the remaining components with optional edges
        // We want to use the strongest possible edges first (after potential upgrade)
        List<Edge> usedOptionalEdges = new ArrayList<>();
        for (Edge edge : optionalEdges) {
            if (uf.union(edge.u, edge.v)) {
                usedOptionalEdges.add(edge);
                if (uf.count == 1) {
                    break;
                }
            }
        }

        // If still not connected, return -1
        if (uf.count != 1) {
            return -1;
        }

        // Now, we have a spanning tree consisting of must edges and some optional edges
        // We need to maximize the minimum strength by upgrading some optional edges

        // Collect all edges in the spanning tree
        List<Edge> spanningTreeEdges = new ArrayList<>();
        spanningTreeEdges.addAll(mustEdges);
        spanningTreeEdges.addAll(usedOptionalEdges);

        // Sort all edges by ascending strength (original or upgraded)
        Collections.sort(spanningTreeEdges, (a, b) -> {
            int aStrength = a.must == 1 ? a.s : (upgradesLeft > 0 ? a.s * 2 : a.s);
            int bStrength = b.must == 1 ? b.s : (upgradesLeft > 0 ? b.s * 2 : b.s);
            return Integer.compare(aStrength, bStrength);
        });

        // Now, we can try to upgrade edges to maximize the minimum strength
        // The idea is to upgrade the strongest edges first to maximize the min strength
        // So we sort the optional edges in descending order of strength
        Collections.sort(optionalEdges, (a, b) -> Integer.compare(b.s, a.s));

        // Apply upgrades to the strongest edges (that are in the spanning tree and not must)
        int appliedUpgrades = 0;
        for (Edge edge : optionalEdges) {
            if (appliedUpgrades >= upgradesLeft) {
                break;
            }
            if (spanningTreeEdges.contains(edge)) {
                edge.s *= 2;
                appliedUpgrades++;
            }
        }

        // Now, find the minimum strength in the spanning tree
        int minStrength = Integer.MAX_VALUE;
        for (Edge edge : spanningTreeEdges) {
            minStrength = Math.min(minStrength, edge.s);
        }

        return minStrength;
    }

    static class Edge {
        int u, v, s, must;
        Edge(int u, int v, int s, int must) {
            this.u = u;
            this.v = v;
            this.s = s;
            this.must = must;
        }
    }

    static class UnionFind {
        int[] parent;
        int[] rank;
        int count;

        UnionFind(int n) {
            parent = new int[n];
            rank = new int[n];
            count = n;
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        boolean union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX == rootY) {
                return false;
            }
            if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
            count--;
            return true;
        }
    }
}
