import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        long hi = 0;
        for (long[] edge : edges) {
            if (edge[3] == 1) {
                hi = Math.max(hi, edge[2]);
            } else {
                hi = Math.max(hi, 2 * edge[2]);
            }
        }
        long lo = 1;
        long ans = -1;

        while (lo <= hi) {
            long mid = lo + (hi - lo) / 2;
            if (check(mid, (int) n, edges, k)) {
                ans = mid;
                lo = mid + 1;
            } else {
                hi = mid - 1;
            }
        }
        return ans;
    }

    private static boolean check(long X, int n, long[][] edges, long k) {
        int[] parent = new int[n];
        int[] rank = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
        int components = n;

        for (long[] edge : edges) {
            if (edge[3] == 1) {
                long s = edge[2];
                if (s < X) {
                    return false;
                }
                int u = (int) edge[0];
                int v = (int) edge[1];
                int ru = find(parent, u);
                int rv = find(parent, v);
                if (ru == rv) {
                    return false;
                }
                if (rank[ru] < rank[rv]) {
                    parent[ru] = rv;
                } else if (rank[rv] < rank[ru]) {
                    parent[rv] = ru;
                } else {
                    parent[rv] = ru;
                    rank[ru]++;
                }
                components--;
            }
        }

        for (long[] edge : edges) {
            if (edge[3] == 0) {
                long s = edge[2];
                if (s >= X) {
                    int u = (int) edge[0];
                    int v = (int) edge[1];
                    int ru = find(parent, u);
                    int rv = find(parent, v);
                    if (ru != rv) {
                        if (rank[ru] < rank[rv]) {
                            parent[ru] = rv;
                        } else if (rank[rv] < rank[ru]) {
                            parent[rv] = ru;
                        } else {
                            parent[rv] = ru;
                            rank[ru]++;
                        }
                        components--;
                    }
                }
            }
        }

        int upgradesUsed = 0;
        for (long[] edge : edges) {
            if (edge[3] == 0) {
                long s = edge[2];
                if (2 * s >= X) {
                    int u = (int) edge[0];
                    int v = (int) edge[1];
                    int ru = find(parent, u);
                    int rv = find(parent, v);
                    if (ru != rv) {
                        if (rank[ru] < rank[rv]) {
                            parent[ru] = rv;
                        } else if (rank[rv] < rank[ru]) {
                            parent[rv] = ru;
                        } else {
                            parent[rv] = ru;
                            rank[ru]++;
                        }
                        components--;
                        upgradesUsed++;
                    }
                }
            }
        }

        if (components != 1) {
            return false;
        }
        return upgradesUsed <= k;
    }

    private static int find(int[] parent, int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
}
